insert into catalog_services (id, section, name, plain_name, description, essential, handler, handler_why, evidence, compliance, metric, prices, goal_plays, fit, pieces, status, sort_order) values
  ('gbp-setup', 'foundation', 'Google Business Profile setup & optimization', 'Show up on Google', 'Claim/verify, correct categories & attributes, hours, menu link, photo set, services — done to rank.', true, 'apnosh', 'Category and attribute choices move ranking; a wrong edit can suppress the listing. Technical and trust-sensitive.', 'GBP is the #1 local discovery surface; +1 review star ≈ 5–9% revenue for independents (Luca, HBS).', null, '{"label":"Calls & direction requests from Google","expect":"More profile actions within 30–60 days of a complete profile"}'::jsonb, '[{"amount":365,"kind":"one-time","cost":{"us":1.5,"offshore":2},"market":{"low":300,"high":500,"label":"professional GBP builds"}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"lean","weight":6,"role":"Complete your Google listing so neighbors searching for tacos actually find you.","because":"Most first-time guests look you up before deciding; a half-built profile quietly loses every one of those searches."},{"goal":"reviews","stage":"listing","minTier":"lean","weight":3,"role":"Get your Google profile complete and correct, since that is where your star rating lives."}]'::jsonb, '{"avoid":{"ghost":"No walk-ins to capture — delivery-platform ranking is the surface that matters.","foodTruck":"Moving trucks run on Google’s service-area rules — needs the truck playbook, not the storefront one."}}'::jsonb, null, 'active', 0),
  ('review-claim', 'foundation', 'Review platforms claim & audit', 'Claim your review pages', 'Claim Yelp & TripAdvisor, fix listing data, flag policy-violating reviews, set alerting.', true, 'apnosh', 'Ownership disputes and flagging run through human support channels — judgment work.', 'For tourist trade, TripAdvisor is the discovery channel: 77% more likely to book when owners respond (Ipsos, 23K travelers).', null, null, '[{"amount":195,"kind":"one-time","cost":{"us":0.75,"offshore":1.25}}]'::jsonb, '[{"goal":"reviews","stage":"listing","minTier":"lean","weight":2,"role":"Claim Yelp and TripAdvisor and fix the listings, the other places your rating shows."}]'::jsonb, '{"great":["seasonal"]}'::jsonb, null, 'active', 1),
  ('site-menu', 'foundation', 'Website & menu tune-up', 'Fix your site & menu', 'Mobile-fast site, HTML menu (not a PDF), hours, location, one-tap call/directions/reserve.', true, 'apnosh', 'The first impression for most guests — built and QA’d by a person on real phones.', '77% check the website and 83% the menu before a first visit.', null, '{"label":"Menu views that turn into visits","expect":"Lower mobile bounce; more one-tap calls & directions"}'::jsonb, '[{"amount":575,"kind":"one-time","cost":{"us":2,"offshore":5},"market":{"low":2000,"high":5000,"label":"agency site builds"}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"lean","weight":3,"role":"A fast site and a readable menu — the page they check right before deciding to come.","because":"77% check the website and 83% read the menu before a first visit."}]'::jsonb, '{"avoid":{"multi":"Multi-location needs per-location pages with unique content — a different build, priced per location."}}'::jsonb, null, 'active', 2),
  ('website-care', 'foundation', 'Website care & updates', 'Keep your site fresh', 'Hosting watch, menu/hours/event updates within a day, monthly speed & uptime check.', false, 'hybrid', 'Routine updates run offshore; a US lead QAs anything guest-facing.', 'Platform competitors charge $119–249/mo for site + care; a one-time build leaves the upkeep unowned.', null, null, '[{"amount":130,"kind":"monthly","cost":{"us":0.25,"offshore":1,"tools":15},"market":{"low":119,"high":249,"label":"platform site + care plans"}}]'::jsonb, null, null, null, 'active', 3),
  ('tracking', 'foundation', 'Tracking & analytics baseline', 'Turn on tracking', 'Set up the tools that count your calls, directions, and orders, plus a starting snapshot to measure against.', true, 'apnosh', 'Mis-wired tracking poisons every later decision. Set up once, correctly.', null, null, '{"label":"The measuring stick itself","expect":"Every other line on the plan gets a number — so we can prove what works and drop what doesn’t"}'::jsonb, '[{"amount":365,"kind":"one-time","cost":{"us":1.5,"offshore":1.5}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"standard","weight":2,"role":"Measure every move, so we scale what brings people in and cut what does not."},{"goal":"nights","stage":"lock","minTier":"lean","weight":4,"role":"Count covers on the named night before and after, so you can tell if any of this worked.","because":"A capacity goal lives or dies on one number: covers on the slow shift."},{"goal":"regulars","stage":"own","minTier":"lean","weight":4,"role":"Shows repeat visits, spend-per-guest, and what each send actually drove."}]'::jsonb, null, null, 'active', 4),
  ('crm-list', 'foundation', 'CRM & guest list setup', 'Set up your guest list', 'Stand up the CRM, import and de-dupe the list, segments (new / regular / lapsed), tagging scheme.', true, 'apnosh', 'Data hygiene decisions (merge rules, segment definitions) need a human owner.', null, null, '{"label":"Contacts you own","expect":"A growing list no algorithm can take away from you"}'::jsonb, '[{"amount":395,"kind":"one-time","cost":{"us":1.5,"offshore":3}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"aggressive","weight":3,"role":"A real guest list with new, regular and lapsed segments."},{"goal":"nights","stage":"activate","minTier":"lean","weight":7,"role":"Get your guest list in one place and tag who comes on weeknights, so you can aim the nudge."},{"goal":"regulars","stage":"own","minTier":"lean","weight":6,"role":"Your guest list in one place — the asset every reward and reminder runs on."}]'::jsonb, null, null, 'active', 5),
  ('email-found', 'foundation', 'Email domain & ESP setup', 'Set up your email', 'Get your business email set up the right way so your messages reach inboxes, not spam.', true, 'apnosh', 'DNS and deliverability are unforgiving — one wrong record lands everything in spam.', null, null, null, '[{"amount":250,"kind":"one-time","cost":{"us":1,"offshore":1.5},"passthrough":"ESP per-contact fees billed at cost"}]'::jsonb, '[{"goal":"regulars","stage":"own","minTier":"lean","weight":3,"role":"Your sending email set up clean so messages land in inboxes, not spam."}]'::jsonb, null, null, 'active', 6),
  ('sms-found', 'foundation', 'SMS number & compliance setup', 'Set up texting', 'Get a texting number set up the legal way, with sign-up wording and quiet hours built in.', true, 'apnosh', 'TCPA violations carry per-message fines. Compliance is liability — never AI-only.', null, 'TCPA + A2P 10DLC registration handled and documented.', null, '[{"amount":310,"kind":"one-time","cost":{"us":1.25,"offshore":1,"tools":10},"passthrough":"Message volume billed at cost (~$30–60/mo per 1,000 subscribers)"}]'::jsonb, '[{"goal":"regulars","stage":"own","minTier":"standard","weight":2,"role":"Compliant texting set up so you can reach regulars where they actually look."}]'::jsonb, null, null, 'active', 7),
  ('brand-kit', 'foundation', 'Brand kit & voice guide', 'Your look and voice', 'Logo lockups, colors, fonts, photo style, and the written voice every AI draft is held to.', true, 'hybrid', 'AI explores directions and drafts the voice guide fast; an Apnosh designer makes the final call.', null, null, null, '[{"amount":360,"kind":"one-time","cost":{"us":1.5,"offshore":1.5,"tools":5}}]'::jsonb, null, '{"avoid":{"multi":"Franchisees inherit brand standards — a new kit can violate the franchise agreement."}}'::jsonb, null, 'active', 8),
  ('channel-connect', 'foundation', 'Channel connection', 'Connect your accounts', 'Connect each account (Facebook, Google, TikTok) so we can post on your behalf.', true, 'apnosh', 'Account access and permissions — a human walks the owner through it.', null, null, null, '[{"amount":95,"kind":"per-unit","unit":"channel","cost":{"us":0.4,"offshore":0.5}}]'::jsonb, null, null, null, 'active', 9),
  ('listings-sync', 'foundation', 'Listings & menu sync', 'Same info everywhere', 'Hours, holidays, menu and photos kept identical across Google, Yelp, Apple Maps and Facebook.', true, 'hybrid', 'Sync tooling does the propagation; a human owns the source of truth and catches conflicts.', 'A whole product category (Marqii, $75–150/location/mo) exists because menu drift across platforms loses orders.', null, '{"label":"Listing accuracy everywhere","expect":"Zero wrong-hours complaints; identical menu on every platform"}'::jsonb, '[{"amount":195,"kind":"one-time","cost":{"us":0.75,"offshore":1.25}},{"amount":115,"kind":"monthly","cost":{"us":0.25,"offshore":1,"tools":10},"market":{"low":75,"high":150,"label":"Marqii-class listings sync"}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"aggressive","weight":1,"role":"Keep Yelp, Apple Maps and Facebook identical to Google so no one hits stale hours."},{"goal":"reviews","stage":"listing","minTier":"aggressive","weight":1,"role":"Keep your hours and info identical everywhere so wrong details do not drag the rating down."}]'::jsonb, '{"great":["multi"]}'::jsonb, null, 'active', 10),
  ('photo-library', 'foundation', 'Food photography library', 'Pro photos of your food', 'One styled shoot → ~30 edited stills covering the menu — feeds GBP, the site, delivery apps and social.', true, 'apnosh', 'A real shoot with art direction — the asset every other channel reuses. AI can’t photograph your food.', 'Bad food photos deter ~36% of diners; item photos lift delivery sales up to 44% (DoorDash, platform-reported).', null, '{"label":"Conversion wherever your food is seen","expect":"Platform-reported: item photos lift delivery sales up to 44%"}'::jsonb, '[{"amount":1050,"kind":"one-time","cost":{"batchedShoots":1,"us":1,"offshore":1},"market":{"low":500,"high":3000,"label":"restaurant menu shoots"}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"standard","weight":4,"role":"One birria shoot that makes every channel look as good as the food tastes.","because":"Bad photos deter about a third of diners; this one asset fuels Google, the site, the creator, and the booth."},{"goal":"reviews","stage":"listing","minTier":"standard","weight":1,"role":"Fresh photos so the listing your rating sits on looks as good as the food."}]'::jsonb, '{"great":["ghost","fineDining"]}'::jsonb, '[{"label":"edited food photo","qty":30}]'::jsonb, 'active', 11),
  ('ordering-setup', 'foundation', 'Order and booking on your site', 'Take orders on your site', 'Let guests order or book straight from your own site instead of paying the apps.', false, 'apnosh', 'Payments, menus and POS integration — technical execution determines whether it works.', 'Third-party platforms take 15–30% per order; direct reorder rates run 2x+ third-party.', null, '{"label":"Commission-free direct orders","expect":"Direct orders replacing the 15–30% platform take"}'::jsonb, '[{"amount":525,"kind":"one-time","cost":{"us":2.5,"offshore":1.5}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"standard","weight":3,"role":"Let a new guest order or book on your own site so you keep the relationship, not the app."}]'::jsonb, '{"great":["ghost","qsr"]}'::jsonb, null, 'active', 12),
  ('video-engine', 'awareness', 'Short-form video engine', 'Short-form video', '8 videos/mo from one batched on-site shoot — shot, edited, captioned, posted to IG + TikTok. Volume pricing (Standard tier): ~$275/video at 4/mo · $175 at 8/mo · $145 at 12/mo.', true, 'hybrid', 'The shoot needs a person on-site — no AI substitute. Template-driven AI-assisted edits with a human finish; one revision round included.', 'Short-form video is a top discovery surface for younger diners (TikTok/Reels). Reach now rewards original, share-worthy footage — platforms downrank generic/recycled content, so cadence alone won’t carry it.', null, '{"label":"Reach, profile visits & follows","expect":"Discovery compounds over 60–90 days — not overnight"}'::jsonb, '[{"amount":1395,"kind":"monthly","cost":{"batchedShoots":1,"us":1.5,"offshore":6,"tools":25},"market":{"low":2000,"high":8000,"label":"retainers for 4–8 videos/mo"}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"aggressive","weight":5,"role":"A steady stream of short videos, the format that puts your food in front of the most new people."}]'::jsonb, '{"great":["neighborhood","cafe"]}'::jsonb, '[{"label":"short video (reel + TikTok)","qty":8}]'::jsonb, 'active', 13),
  ('video-single', 'awareness', 'Short-form video (dedicated shoot)', 'One short video', 'One reel/TikTok with its own shoot visit. Un-batched, so it carries the full shoot minimum — the engine is the better buy.', false, 'hybrid', 'Same pipeline as the engine; a solo shoot visit carries the 2-hr minimum + travel that shooters actually bill.', null, null, null, '[{"amount":1195,"kind":"per-unit","unit":"video","cost":{"soloShoots":1,"us":0.5,"offshore":1,"tools":3},"market":{"low":300,"high":1500,"label":"pro per-video rates"}}]'::jsonb, null, null, '[{"label":"short video","qty":1}]'::jsonb, 'active', 14),
  ('social-mgmt', 'awareness', 'Social posting & community management', 'Run your social', '12 feed posts/mo scheduled + comments and DMs answered within a day.', true, 'hybrid', 'AI drafts posts and reply suggestions; offshore schedules; a US lead curates and takes the tricky conversations.', 'Market band for this exact scope is $500–1,500/mo; restaurant freelancers start ~$900.', null, '{"label":"Engaged local following","expect":"Consistent presence; comments & DMs answered within a day"}'::jsonb, '[{"amount":475,"kind":"monthly","cost":{"us":1.5,"offshore":4,"tools":10},"market":{"low":500,"high":1500,"label":"same scope, freelance–agency"}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":3,"role":"Keep your social pages active so new neighbors who check you out see a place worth visiting."}]'::jsonb, null, '[{"label":"social post","qty":12}]'::jsonb, 'active', 15),
  ('gbp-posts', 'awareness', 'GBP posts & Q&A', 'Keep Google fresh', '4 Google Business posts/mo + Q&A answers, generated from your menu and events.', true, 'ai', 'Formulaic, grounded in your own data — AI output matches human quality here. 15-minute human QA before publish.', null, null, '{"label":"Google profile actions","expect":"An active profile holds its place in local results"}'::jsonb, '[{"amount":85,"kind":"monthly","cost":{"us":0.25,"offshore":0.75,"tools":3},"market":{"low":125,"high":400,"label":"GBP management retainers"}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":3,"role":"Keep the Google listing active with the current offer so it holds its rank."},{"goal":"nights","stage":"activate","minTier":"lean","weight":5,"role":"Post the weeknight draw on your Google profile so locals searching nearby see it."}]'::jsonb, '{"avoid":{"ghost":"No walk-ins — put this effort into delivery-platform listings instead."}}'::jsonb, '[{"label":"Google post","qty":4}]'::jsonb, 'active', 16),
  ('local-seo', 'awareness', 'Local SEO & citations', 'Rank in local search', 'Get your name, address, and phone matching everywhere online, then watch your local ranking each month.', true, 'apnosh', 'Cleanup is investigative work across dozens of directories; monitoring needs judgment on what to fix.', 'Basic local-SEO retainers run $300–800/mo; ours is narrow-scope monitoring on top of a clean setup.', null, null, '[{"amount":365,"kind":"one-time","cost":{"us":1.5,"offshore":2}},{"amount":150,"kind":"monthly","cost":{"us":0.5,"offshore":1,"tools":5},"market":{"low":300,"high":800,"label":"basic local-SEO retainers"}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"standard","weight":4,"role":"Get your name and address matching everywhere so locals searching nearby actually find you."}]'::jsonb, '{"great":["multi"],"avoid":{"ghost":"Resident-radius SEO targets walk-ins a ghost kitchen doesn’t serve."}}'::jsonb, null, 'active', 17),
  ('delivery-opt', 'awareness', 'Delivery platform optimization', 'Win on delivery apps', 'DoorDash/UberEats/Grubhub listings done right — item photos, descriptions, menu structure — then monthly promo & sponsored-listing management.', false, 'hybrid', 'AI drafts descriptions at volume; Apnosh runs the platform levers (promos, ads, ratings) where mistakes cost real dollars.', 'Item photos up to +44% monthly sales, descriptions +18% (DoorDash 15K-merchant study; platform-reported). For delivery-led concepts this is the discovery channel.', null, '{"label":"Delivery orders & menu conversion","expect":"Platform-reported: photos +44%, descriptions +18% monthly sales"}'::jsonb, '[{"amount":385,"kind":"one-time","cost":{"us":1.5,"offshore":2.5}},{"amount":245,"kind":"monthly","cost":{"us":1,"offshore":1,"tools":5},"note":"sponsored-listing spend billed at cost"}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":4,"role":"Fix your DoorDash and Uber Eats listings, the discovery shelf for delivery-first guests."}]'::jsonb, '{"great":["ghost","qsr"]}'::jsonb, null, 'active', 18),
  ('paid-ads', 'awareness', 'Paid local ads management', 'Local ads', 'Geo-targeted Meta + Google campaigns: setup, creative rotation, weekly optimization.', false, 'apnosh', 'Ads punish mistakes in real dollars daily. AI tools assist inside the platform; accountability stays human.', 'Restaurant CPCs: Google ≈ $2.05, Meta ≈ $0.72. Agencies won’t touch management below $500/mo.', 'Alcohol ads: Meta requires 21+ targeting; Google’s alcohol policy applies; some states restrict drink promos.', '{"label":"Cost per new customer","expect":"Knowable within 2–4 weeks — and we kill what doesn’t pay"}'::jsonb, '[{"amount":545,"kind":"monthly","note":"ad spend billed at cost, $500/mo minimum","cost":{"us":2.5,"offshore":1,"tools":10},"market":{"low":500,"high":1500,"label":"small-local PPC management"}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"aggressive","weight":1,"role":"Boost whichever move already proved it converts — never spend cold."},{"goal":"nights","stage":"activate","minTier":"aggressive","weight":1,"role":"A tight geo boost on the slow-night offer to top up covers when the draw plus nudges fall short."}]'::jsonb, null, null, 'active', 19),
  ('creator-collab', 'awareness', 'Local creator collab', 'Team up with a creator', 'Source, vet and brief a local food creator; coordinate the visit and the post.', false, 'apnosh', 'Vetting people and negotiating terms is relationship work.', null, null, null, '[{"amount":595,"kind":"per-unit","unit":"activation","note":"creator fee billed at cost","cost":{"us":3,"offshore":0.5}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":4,"role":"A trusted Mission food creator puts your birria in front of their local audience.","because":"Borrowed, already-trusting reach — the biggest single source of net-new awareness for a spot nobody knows yet."}]'::jsonb, '{"avoid":{"qsr":"Creator “come visit” content underperforms for QSR — loyalty and delivery channels move the number."}}'::jsonb, null, 'active', 20),
  ('nextdoor-local', 'awareness', 'Neighborhood presence', 'Show up for neighbors', 'Claim and run the Nextdoor Business Page and take part in the real local Facebook groups where nearby residents ask for recommendations — value-first, never fake recs.', false, 'hybrid', 'A US lead claims the page and sets positioning; offshore publishes and monitors threads under QA. Posting in someone else’s community is reputational — judgment, not generation.', 'The most literally on-target channel for neighbors who don’t know you exist. Structural limits (~2 free posts/mo, invisible until the first real recommendation) make it an always-on floor, not a spike.', 'No fake recommendations or sock-puppet neighbor endorsements (Nextdoor / Meta policy); we only ask real, happy in-house guests to recommend.', '{"label":"Net-new neighbors reached","expect":"A slow compounding trickle once the page earns its first recommendation — not a launch spike"}'::jsonb, '[{"amount":245,"kind":"one-time","cost":{"us":1.5,"offshore":1}},{"amount":115,"kind":"monthly","cost":{"us":0.25,"offshore":2.5},"note":"any Nextdoor ad spend billed at cost"}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"lean","weight":6,"role":"Show up where neighbors literally ask for taco recommendations."},{"goal":"nights","stage":"activate","minTier":"standard","weight":2,"role":"Light geo reach to nearby neighbors who do not know about the weeknight thing yet."}]'::jsonb, '{"great":["neighborhood","cafe"],"avoid":{"ghost":"No walk-in radius to win — delivery listings matter instead.","seasonal":"A resident-recommendation channel does little for one-time tourists."}}'::jsonb, null, 'active', 21),
  ('street-sampling', 'awareness', 'Sampling booth at local events', 'Sample at local events', 'Scout and book the right neighborhood events, handle the permit paperwork, and run a turnkey “taste it” booth with a QR + first-visit offer that captures contacts on the spot.', false, 'apnosh', 'Event vetting, permits and on-site logistics are hands-on ops and relationship work — the least automatable kind.', 'The most trust-dense channel for a thin-listing spot: a warm bite converts strangers a banner ad can’t, and it builds the list this business doesn’t have. Direct conversion evidence is analogical — frame early events as a measured test.', 'A local temporary-food-event permit is required to hand out samples (budget + lead time per event), or book only under a sponsor umbrella permit. Booth, permit and food billed at cost.', '{"label":"Sampled guests who become first visits","expect":"High trust per taste, but calendar- and weather-bound — run the first 2-3 as a tracked test"}'::jsonb, '[{"amount":695,"kind":"one-time","cost":{"us":2.5,"offshore":8,"tools":120}},{"amount":195,"kind":"per-unit","unit":"event","cost":{"us":0.5,"offshore":3},"note":"booth, permit and food billed at cost"}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"lean","weight":5,"role":"Let new neighbors taste the birria at local events — the most trust-dense first visit there is."}]'::jsonb, '{"great":["foodTruck","neighborhood","cafe"],"avoid":{"ghost":"No storefront to drive a sampled guest back to."}}'::jsonb, null, 'active', 22),
  ('cross-promo', 'awareness', 'Neighbor cross-promo partnerships', 'Team up with neighbors', 'Map non-competing businesses a short walk away (a kitchen-less brewery first), design a simple reciprocal offer or staff-meal deal, and set up the cards so each one quietly sends you their people.', false, 'apnosh', 'Partner outreach and negotiating reciprocal terms is relationship work; offshore handles scheduling and asset production.', 'A resident-base analogue of the concierge play. Strongest for a kitchen-less taproom (hungry, deciding now); otherwise thin and analogical, so sell the signed partnerships, never an ROI.', null, '{"label":"Signed local partners + referred guests","expect":"A steady supplement, not a driver — yield is partner-dependent and slow to ramp"}'::jsonb, '[{"amount":310,"kind":"one-time","cost":{"us":1.75,"offshore":3.5,"tools":30}},{"amount":95,"kind":"monthly","cost":{"us":0.4,"offshore":1.5}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":2,"role":"Standing deals with nearby spots (a kitchen-less brewery first) that send you their people."}]'::jsonb, '{"great":["neighborhood","bar","cafe"],"avoid":{"seasonal":"Residents already have taco habits; tourist channels matter more for a seasonal spot."}}'::jsonb, null, 'active', 23),
  ('pr-media', 'awareness', 'PR & earned media outreach', 'Get in the news', 'Story mining (founder, recipes, openings), a press kit, and pitches to local food press & critics.', false, 'apnosh', 'Editor relationships and judgment about what’s actually a story — not a generation task.', 'The growth lever for chef-driven rooms; immigrant-founder stories are exactly what local food editors want.', null, '{"label":"Press placements","expect":"Earned media compounds — but no placement is ever guaranteed"}'::jsonb, '[{"amount":750,"kind":"per-unit","unit":"campaign","cost":{"us":4},"market":{"low":1500,"high":5000,"label":"restaurant PR retainers (per month)"}}]'::jsonb, null, '{"great":["fineDining","neighborhood","preOpening"]}'::jsonb, null, 'active', 24),
  ('truck-location', 'awareness', 'Location broadcasting & schedule sync', 'Tell fans where you are', '“Where are we today” published everywhere daily — site calendar, social, SMS list, and truck-locator apps.', false, 'hybrid', 'AI formats the daily posts from your schedule; offshore publishes; you just keep the calendar true.', 'The #1 daily marketing job for a truck; locator apps (StreetFoodFinder, Truckster) push to fans when you’re near.', null, '{"label":"“Where are you today?” answered","expect":"Fans find you daily without asking"}'::jsonb, '[{"amount":135,"kind":"monthly","cost":{"us":0.25,"offshore":1.5,"tools":10}}]'::jsonb, null, '{"great":["foodTruck"]}'::jsonb, null, 'active', 25),
  ('graphic', 'awareness', 'Event graphic / promo design', 'A graphic for your event', 'A scroll-stopping designed graphic for the moment — sized for Google, social and the event page.', false, 'hybrid', 'AI explores layouts fast; an Apnosh designer makes the final, on-brand call. One revision included.', 'One strong graphic is the asset every channel reuses — the same design carries Google, social and the Facebook event page.', null, '{"label":"Saves & shares of the announcement","expect":"A clear, on-brand graphic earns more saves than a plain photo"}'::jsonb, '[{"amount":85,"kind":"one-time","cost":{"us":0.25,"offshore":0.5,"tools":2},"market":{"low":50,"high":200,"label":"freelance graphic design"}}]'::jsonb, null, null, null, 'active', 26),
  ('gbp-event-post', 'awareness', 'Google event post', 'Post your event on Google', 'A dated event post on your Google Business Profile so it shows in Search & Maps on the right days.', false, 'ai', 'Formulaic and grounded in your event details — AI drafts, a human QAs before publish.', 'Google event posts put your event in front of locals searching your area on the exact dates they’re looking.', null, '{"label":"Google event views & clicks","expect":"Extra profile actions in the days around the event"}'::jsonb, '[{"amount":45,"kind":"one-time","cost":{"us":0.15,"offshore":0.25,"tools":1},"market":{"low":40,"high":150,"label":"per-post GBP management"}}]'::jsonb, null, null, null, 'active', 27),
  ('fb-event', 'awareness', 'Facebook event page', 'A Facebook event page', 'A real Facebook event page: invite your followers, show who’s going, auto-remind everyone who responds.', false, 'hybrid', 'We set up the page, artwork and details; the platform handles the invites and reminders.', 'A Facebook event page invites your followers, shows them which friends are going, and auto-reminds attendees — organic reach you can’t buy.', null, '{"label":"Event responses & shares","expect":"RSVPs and friend-of-attendee reach that compounds as people respond"}'::jsonb, '[{"amount":65,"kind":"one-time","cost":{"us":0.25,"offshore":0.5},"market":{"low":50,"high":150,"label":"event-page setup"}}]'::jsonb, null, null, null, 'active', 28),
  ('capture-kit', 'capture', 'In-store capture kit', 'Grow your guest list', 'QR table tents, counter cards and receipt inserts that trade an incentive for a contact.', true, 'hybrid', 'AI writes the offer copy variants; Apnosh designs, prints and places them.', 'The list you own is the only channel without an algorithm or a toll.', null, '{"label":"Contacts captured per week","expect":"Steady signups from tables and the counter"}'::jsonb, '[{"amount":295,"kind":"one-time","cost":{"us":1,"offshore":1.5,"tools":15}}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"lean","weight":5,"role":"Start the guest list every new walk-in feeds, so you stop renting the relationship."},{"goal":"nights","stage":"activate","minTier":"lean","weight":4,"role":"Table tents and QR so people who show up on the slow night join the list for next week."},{"goal":"regulars","stage":"own","minTier":"lean","weight":5,"role":"Table tents, QR and counter sign-ups that turn anonymous diners into known guests."}]'::jsonb, '{"avoid":{"ghost":"No storefront — bag inserts via delivery optimization do this job instead.","foodTruck":"No counter context — window decal + bag inserts instead.","fineDining":"Table-tent QR codes clash with the service model — capture through the reservation platform."}}'::jsonb, null, 'active', 29),
  ('landing-page', 'capture', 'Offer landing page & signup form', 'A signup page for your offer', 'A single fast page: the offer, the form, the confirmation — wired into the CRM.', true, 'hybrid', 'AI drafts the copy; Apnosh builds the page, wires the form and tests the whole path.', 'The page that turns interest into a contact you own — the only channel without an algorithm between you and the guest.', null, '{"label":"RSVPs / signups captured","expect":"A list of who’s coming, so you can fill the rest of the room"}'::jsonb, '[{"amount":275,"kind":"one-time","cost":{"us":1,"offshore":2,"tools":3},"market":{"low":150,"high":600,"label":"freelance landing pages"}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"standard","weight":4,"role":"One fast page where a new guest grabs your offer and joins your list."}]'::jsonb, null, null, 'active', 30),
  ('incentive-design', 'capture', 'Signup incentive design', 'Pick the right giveaway', 'Pick the giveaway (free app, dessert, % off) with the marginal-cost math to keep it profitable.', true, 'apnosh', 'The offer math against your food cost is judgment, not generation.', null, null, null, '[{"amount":240,"kind":"one-time","cost":{"us":1.25}}]'::jsonb, '[{"goal":"regulars","stage":"reward","minTier":"lean","weight":8,"role":"Designs the reward math so offers drive return visits without giving away margin."}]'::jsonb, '{"avoid":{"fineDining":"Discount mechanics undercut the price premium the brand is built on."}}'::jsonb, null, 'active', 31),
  ('ai-phone', 'capture', 'AI phone and missed-call text back', 'Never miss a call', 'Every call answered: hours, menu and directions handled by AI; bookings and complaints escalated to a human; missed calls get an instant text.', false, 'ai', 'This product is AI — with a hard human-escalation path for anything sensitive.', 'A fast-growing line at Popmenu/Podium — every missed call at dinner rush is a lost cover.', null, '{"label":"Missed calls recovered","expect":"Every missed dinner-rush call gets an instant text"}'::jsonb, '[{"amount":310,"kind":"one-time","cost":{"us":1.5,"offshore":0.5}},{"amount":105,"kind":"monthly","cost":{"us":0.2,"offshore":0.25,"tools":20},"passthrough":"call-minute fees billed at cost","market":{"low":99,"high":300,"label":"AI answering add-ons"}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"aggressive","weight":2,"role":"Answer every call and text back missed ones so a first-timer trying to reach you never slips away."}]'::jsonb, null, null, 'active', 32),
  ('pre-opening', 'capture', 'Pre-opening launch package', 'Open with a crowd', 'The 8-week ladder: coming-soon page + list building, GBP live 90 days pre-open, countdown content, staged soft opening, opening press push.', false, 'apnosh', 'A sequenced campaign with hard dates — orchestration, not generation.', 'Google publishes profiles 90 days before opening (documented mechanic); opening-surge guests must be captured before the year-two slump.', null, '{"label":"Opening-week covers & list size","expect":"300–500 contacts before doors open is the working target"}'::jsonb, '[{"amount":1295,"kind":"one-time","cost":{"us":6,"offshore":4}}]'::jsonb, null, '{"great":["preOpening"]}'::jsonb, null, 'active', 33),
  ('welcome-seq', 'nurture', 'Welcome sequence', 'Welcome new guests', '3 emails + 1 SMS over the first two weeks: story, menu favorites, a reason to come back.', true, 'hybrid', 'AI drafts all four messages in your voice; Apnosh edits, builds and QA-sends.', null, null, '{"label":"New signups who come back","expect":"Every new contact nudged back within two weeks"}'::jsonb, '[{"amount":395,"kind":"one-time","cost":{"us":1.5,"offshore":2.5,"tools":3}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"aggressive","weight":2,"role":"A warm first-touch so a captured contact comes back."},{"goal":"regulars","stage":"lifecycle","minTier":"lean","weight":5,"role":"A short automatic intro series that starts the relationship the moment someone joins."}]'::jsonb, '{"avoid":{"preOpening":"No guests yet — the launch package’s countdown sequence is the pre-open version."}}'::jsonb, '[{"label":"welcome email","qty":3},{"label":"welcome text","qty":1}]'::jsonb, 'active', 34),
  ('second-visit', 'nurture', 'Second-visit nudge automation', 'Win the 2nd visit', 'A timed, incentivized nudge after the first visit — the single highest-leverage automation.', true, 'hybrid', 'AI drafts the message; Apnosh wires the trigger and timing logic.', 'Restaurant revenue concentrates in repeat guests, and the first→second visit is the steepest drop-off — triggered nudges earn ~16–22× more per send than batch blasts (Klaviyo, Omnisend).', null, '{"label":"First-timers who return","expect":"The hinge metric — the first→second visit is the steepest drop-off to fix"}'::jsonb, '[{"amount":260,"kind":"one-time","cost":{"us":1,"offshore":1.5,"tools":3}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"standard","weight":4,"role":"An automatic nudge back for the all-important second visit.","because":"The first-to-second visit is the steepest drop-off in the whole funnel."},{"goal":"nights","stage":"habit","minTier":"lean","weight":3,"role":"After someone comes on the slow night, prompt them to come back to the same night next week."},{"goal":"regulars","stage":"reward","minTier":"lean","weight":9,"role":"An automatic nudge plus offer to pull a first-timer back for visit number two.","because":"The first-to-second visit is the steepest drop-off; the cheapest visits are returning ones."}]'::jsonb, '{"great":["neighborhood","qsr"]}'::jsonb, null, 'active', 35),
  ('newsletter', 'retain', 'Monthly newsletter', 'One good email a month', 'One genuinely good email a month: what’s new, what’s seasonal, one reason to visit.', true, 'hybrid', 'AI drafts from this month’s events and menu; Apnosh edits to earn the open.', 'Restaurant email engagement is low on average — quality over cadence is the whole game.', null, '{"label":"Opens & visits per send","expect":"One good email a month beats four mediocre ones"}'::jsonb, '[{"amount":190,"kind":"monthly","cost":{"us":0.75,"offshore":1,"tools":2},"market":{"low":250,"high":500,"label":"managed newsletter programs"}}]'::jsonb, '[{"goal":"regulars","stage":"lifecycle","minTier":"standard","weight":3,"role":"A regular email that keeps regulars connected to what is new and worth a visit."}]'::jsonb, '{"avoid":{"qsr":"The QSR relationship lives in app push and SMS offers, not editorial email.","bar":"Late-night audiences live on IG/TikTok/SMS — email is the wrong primary channel.","seasonal":"Always-on cadence burns a list that’s dark all off-season — needs pause/re-engage design."}}'::jsonb, '[{"label":"email newsletter","qty":1}]'::jsonb, 'active', 36),
  ('sms-program', 'retain', 'SMS program', 'Text your regulars', '2 segmented sends/mo — slow-night offers, event invites — with strict frequency discipline.', true, 'hybrid', 'AI drafts; Apnosh owns segmentation, timing and compliance on every send.', 'Texts get read fast — but there’s no real “open rate”; track clicks & redemptions. Discipline is the product: 1–2 sends/week max, or over-messaging drives opt-outs.', 'TCPA quiet hours and opt-out honored on every send.', '{"label":"Clicks & redemptions per send","expect":"Track redemptions, not “opens” — and keep frequency to 1–2/week"}'::jsonb, '[{"amount":190,"kind":"monthly","cost":{"us":0.75,"offshore":1,"tools":2},"passthrough":"message volume billed at cost (~$30–60/mo per 1,000 subscribers)","market":{"low":75,"high":185,"label":"software-only SMS (no humans)"}}]'::jsonb, '[{"goal":"nights","stage":"activate","minTier":"lean","weight":6,"role":"Text the list day-of and day-before: \"Tonight is trivia, your table is waiting.\"","because":"Filling a specific night is a timing problem; SMS is the fastest way to move a known audience onto a named date."},{"goal":"regulars","stage":"lifecycle","minTier":"standard","weight":4,"role":"Ongoing texts for specials and reminders — the fastest channel to fill a slot."}]'::jsonb, '{"avoid":{"fineDining":"Promo blasts erode premium positioning — keep SMS transactional (reservations, VIP) only."}}'::jsonb, '[{"label":"segmented text send","qty":2}]'::jsonb, 'active', 37),
  ('offer-eng', 'convert', 'Offer & promo engineering', 'A promo that works', 'Design one promotion properly: the hook, the margin math, menu psychology, the redemption path.', true, 'apnosh', 'Pricing strategy against your food cost is consulting, not content.', 'Menu-psychology effects are real — removing $-signs lifted spend ~8%/check (Cornell field experiment).', null, '{"label":"Redemptions & margin per promo","expect":"Every promo gets a read on whether it actually paid"}'::jsonb, '[{"amount":385,"kind":"per-unit","unit":"campaign","cost":{"us":2}}]'::jsonb, '[{"goal":"firstvisit","stage":"give-reason","minTier":"lean","weight":3,"role":"Turn the free-side idea into a margin-safe, trackable reason to come in now."},{"goal":"nights","stage":"lock","minTier":"lean","weight":3,"role":"Build the slow-night offer so it protects your margin: a bundle or add-on, not a deep discount."}]'::jsonb, null, null, 'active', 38),
  ('menu-eng', 'convert', 'Menu engineering & pricing', 'Make your menu sell more', 'We study which items make you money and lay out your menu and prices so guests spend a bit more.', false, 'apnosh', 'Consulting on your real numbers — AI assists the analysis; the calls are human.', 'Honest framing: the famous “10–15% profit” study doesn’t exist. What’s real: Cornell’s ~8% check lift from price formatting, plus item-mix math on your own POS data.', null, '{"label":"Average check & item mix","expect":"Cornell-tested formatting ≈ +8%/check; mix shifts visible in ~60 days"}'::jsonb, '[{"amount":625,"kind":"one-time","cost":{"us":3,"offshore":1}}]'::jsonb, '[{"goal":"nights","stage":"lock","minTier":"standard","weight":2,"role":"Design a named slow-night feature (a Tuesday plate, a Wednesday flight) so the draw is the food, not a coupon."},{"goal":"regulars","stage":"reward","minTier":"standard","weight":6,"role":"Engineer the menu so regulars trade up: pairings, add-ons, high-margin features.","because":"Frequency brings people back; ticket size only climbs if the menu is built for it."}]'::jsonb, '{"great":["qsr","cafe"]}'::jsonb, null, 'active', 39),
  ('event-pkg', 'anticipation', 'Event / LTO promo package', 'Promote an event', 'Everything one event needs: graphic, email, SMS, GBP post, story — shipped as a set.', false, 'hybrid', 'AI drafts every asset from one brief; Apnosh designs the graphic and ships the set.', null, null, '{"label":"Covers on event nights","expect":"Tue–Thu traffic is the test"}'::jsonb, '[{"amount":385,"kind":"per-unit","unit":"event","cost":{"us":1.5,"offshore":2,"tools":5}}]'::jsonb, '[{"goal":"nights","stage":"draw","minTier":"lean","weight":3,"role":"Run a single themed slow-night event to test which idea lands before committing to a series."}]'::jsonb, null, '[{"label":"graphic","qty":1},{"label":"email","qty":1},{"label":"SMS","qty":1},{"label":"Google post","qty":1},{"label":"story","qty":1}]'::jsonb, 'active', 40),
  ('bar-events', 'convert', 'Weekly events engine', 'Fill your slow weeknights', 'Recurring programming (trivia, music, game-day) promoted properly: monthly calendar + 4 event pushes (graphic, social, SMS, listings).', false, 'hybrid', 'AI drafts the recurring assets from templates; Apnosh runs the calendar and listings distribution.', 'Weekly programming is the bar industry’s weekday traffic lever; per-event pricing breaks at 4+/mo, so this is the bundle.', 'Drink-promo laws vary by state (MA bans time-limited discounts); alcohol ad policies apply.', '{"label":"Weeknight covers","expect":"Recurring programming fills the Tue–Thu trough"}'::jsonb, '[{"amount":525,"kind":"monthly","cost":{"us":2,"offshore":3,"tools":8}}]'::jsonb, '[{"goal":"nights","stage":"draw","minTier":"standard","weight":2,"role":"Stand up recurring weeknight programming (trivia, music, game-day) so there is always a reason to come.","because":"A repeating, calendar-able draw on a specific night beats one-off promos."},{"goal":"regulars","stage":"reward","minTier":"aggressive","weight":3,"role":"Recurring weeknight programming gives regulars a standing reason to keep coming."}]'::jsonb, '{"great":["bar"]}'::jsonb, '[{"label":"event push (graphic, social, SMS, listings)","qty":4}]'::jsonb, 'active', 41),
  ('catering-engine', 'convert', 'Catering & private events engine', 'Land catering jobs', 'Lead capture page, proposal & quote templates, follow-up automation, plus local B2B outreach (offices, planners).', false, 'apnosh', 'B2B sales infrastructure — proposals and outreach need a human owner; AI drafts the documents.', 'Avg catering ticket ~$350 vs ~$35 dine-in; ~10–20% of sales where offered (Technomic); one recurring corporate account ≈ $30–50K/yr.', null, '{"label":"Catering inquiries & booked events","expect":"One recurring corporate account ≈ $30–50K/yr"}'::jsonb, '[{"amount":650,"kind":"one-time","cost":{"us":3,"offshore":2}},{"amount":105,"kind":"monthly","cost":{"us":0.4,"offshore":0.5,"tools":2}}]'::jsonb, null, '{"great":["foodTruck","fineDining","qsr","cafe"]}'::jsonb, null, 'active', 42),
  ('giftcards', 'anticipation', 'Gift card program & Q4 push', 'Sell gift cards', 'Digital + physical gift cards set up, then a dedicated November–December campaign (the season that is half the year’s card sales).', false, 'hybrid', 'POS/program setup is technical; the campaign assets are AI-drafted, human-shipped.', 'Q4 ≈ half of annual restaurant gift-card sales (Paytronix/NRN); ~60% of adults want restaurant cards as gifts; most recipients overspend the card.', 'Unredeemed balances are governed by state escheatment law — breakage is not free money everywhere.', '{"label":"Cards sold (watch Q4)","expect":"Nov–Dec ≈ half the year’s card sales; most recipients overspend the card"}'::jsonb, '[{"amount":325,"kind":"one-time","cost":{"us":1.5,"offshore":1}},{"amount":385,"kind":"per-unit","unit":"campaign","cost":{"us":1.5,"offshore":2,"tools":5}}]'::jsonb, '[{"goal":"regulars","stage":"reward","minTier":"aggressive","weight":2,"role":"Gift cards drive repeat purchase and pull the recipient in as a new regular."}]'::jsonb, '{"great":["fineDining","cafe"]}'::jsonb, null, 'active', 43),
  ('reservation-protect', 'convert', 'No-show protection', 'Cut no-shows', 'Confirmation + day-of reminders with one-tap rebooking, plus deposit / card-hold policy design for peak nights.', false, 'apnosh', 'Reservation-system integration plus policy design — the policy is the higher-leverage half.', 'Reminders cut no-shows ~30–40% (independent RCTs). Deposits cut them further but suppress bookings & feel unfair (Kim 2024) — use holds only for peak or high-cost covers.', null, '{"label":"No-show rate","expect":"Reminders cut no-shows ~40%; deposits ~50% (platform-reported)"}'::jsonb, '[{"amount":385,"kind":"one-time","cost":{"us":2}}]'::jsonb, '[{"goal":"nights","stage":"lock","minTier":"aggressive","weight":1,"role":"Hold and confirm the bookings the offer drives so a busy slow night does not turn into no-shows."}]'::jsonb, '{"great":["fineDining","seasonal"],"avoid":{"qsr":"No reservations in this format.","cafe":"Counter service — nothing to no-show.","foodTruck":"No reservations — catering-inquiry SLAs are the equivalent.","ghost":"No tables at all."}}'::jsonb, null, 'active', 44),
  ('reminder-send', 'convert', 'Reminder send (“book now”)', 'A book-now reminder', 'A timed reminder text or email — “book now / tonight!” — sent to your list a couple days out.', false, 'hybrid', 'AI drafts the message in your voice; Apnosh owns the timing, segment and compliance on every send.', 'A timed “book now” reminder is what turns interest into a reservation — the single send most likely to fill the date.', 'TCPA quiet hours and opt-out honored on every send.', '{"label":"Bookings from the nudge","expect":"A spike in reservations in the 48 hours after the send"}'::jsonb, '[{"amount":40,"kind":"per-unit","unit":"send","cost":{"us":0.1,"offshore":0.4,"tools":1},"passthrough":"message volume billed at cost","market":{"low":25,"high":60,"label":"managed reminder sends"}}]'::jsonb, '[{"goal":"nights","stage":"activate","minTier":"standard","weight":3,"role":"Send a targeted day-before reminder to the segment most likely to come on a weeknight."},{"goal":"regulars","stage":"reward","minTier":"lean","weight":7,"role":"A cheap pay-per-send nudge to fill a mid-week slot — the lowest-cost way to add a visit."}]'::jsonb, null, null, 'active', 45),
  ('review-engine', 'advocate', 'Review request engine', 'Collect fresh reviews', 'Post-visit review invites to every guest, unconditionally — recency is what readers trust.', true, 'apnosh', 'Trigger wiring + staying inside Google/Yelp/FTC rules. Compliance is a human responsibility.', 'Each star ≈ 5–9% revenue for independents (Luca, HBS; replicated by Fang 2022, Management Science). Recency matters — most diners weight reviews from the last ~3 months, so volume must be continuous.', 'No review gating: invites go to every guest regardless of sentiment (Google policy / FTC rule).', '{"label":"New reviews per month","expect":"Recency is the game — 85% of diners ignore reviews older than 3 months"}'::jsonb, '[{"amount":325,"kind":"one-time","cost":{"us":1.5,"offshore":1}}]'::jsonb, '[{"goal":"firstvisit","stage":"give-reason","minTier":"lean","weight":2,"role":"Turn happy guests into the fresh reviews new neighbors actually trust.","because":"Each extra star is worth roughly 5–9% in revenue for an independent, and recent reviews are what new diners weigh."},{"goal":"regulars","stage":"advocate","minTier":"standard","weight":2,"role":"Turns happy repeat visits into a steady flow of public reviews."},{"goal":"reviews","stage":"ask","minTier":"lean","weight":1,"role":"Ask every happy guest for a review, the steady way a rating actually climbs."}]'::jsonb, '{"avoid":{"preOpening":"No guests yet — ships at opening, claimed and monitored from day one."}}'::jsonb, null, 'active', 46),
  ('feedback-loop', 'retain', 'Private guest feedback loop', 'Catch problems privately', 'A post-visit survey that hears problems directly and triggers a same-day recovery playbook — runs alongside (never instead of) public review invites.', true, 'hybrid', 'AI triages and drafts the recovery outreach; a human makes the save.', 'Catching a bad night privately protects the rating that moves revenue 5–9% per star. Recovery done fast keeps the guest.', 'Compliant by design: never gates or filters who gets asked for a public review.', '{"label":"Problems intercepted privately","expect":"Bad nights handled before they reach your rating"}'::jsonb, '[{"amount":345,"kind":"one-time","cost":{"us":1.5,"offshore":1,"tools":5}}]'::jsonb, '[{"goal":"regulars","stage":"advocate","minTier":"standard","weight":3,"role":"Catches unhappy guests privately so you fix issues before they quietly stop coming."},{"goal":"reviews","stage":"intercept","minTier":"lean","weight":1,"role":"Catch an unhappy guest privately and fix it before it becomes a public one-star."}]'::jsonb, '{"great":["fineDining"]}'::jsonb, null, 'active', 47),
  ('review-responses', 'retain', 'Review response management', 'Answer every review', 'Every review on every platform answered in your voice — thanks, recovery, and the public save.', true, 'hybrid', 'AI drafts every response in your voice instantly; a human approves and posts — especially the angry ones.', 'Responding causally lifts ratings (+0.12★) and volume (+12%) (Proserpio & Zervas, Marketing Science) — concentrate on negative reviews; reflexively answering positives can backfire (Wang & Chaudhry, JMR).', null, '{"label":"Rating trend & response rate","expect":"Responding lifts ratings ~+0.12★ and review volume ~+12% over months"}'::jsonb, '[{"amount":165,"kind":"monthly","cost":{"us":0.5,"offshore":1.5,"tools":3},"market":{"low":300,"high":1000,"label":"human done-for-you responses"}}]'::jsonb, '[{"goal":"firstvisit","stage":"give-reason","minTier":"aggressive","weight":1,"role":"Answer every review to lift the rating and show you are present."},{"goal":"reviews","stage":"respond","minTier":"lean","weight":1,"role":"Reply to every review, which lifts the score and shows new guests you are present."}]'::jsonb, '{"great":["seasonal","multi"]}'::jsonb, null, 'active', 48),
  ('loyalty', 'retain', 'Loyalty program', 'Reward your regulars', 'Visit-based rewards tuned to your format (stamps for daily habits, points for tickets): design, POS setup, staff one-pager, monthly care.', true, 'apnosh', 'Reward economics + POS integration; the design mistakes are expensive to unwind.', 'Loyalty members visit more often (NRA: ~70% of operators with programs report higher traffic), though some of that is self-selection — design it to actually change behavior, not just badge your regulars.', null, '{"label":"Repeat-visit rate","expect":"Members visit ~20% more — needs guest volume to pay off"}'::jsonb, '[{"amount":625,"kind":"one-time","cost":{"us":3,"offshore":1}},{"amount":75,"kind":"monthly","cost":{"us":0.25,"offshore":0.75},"market":{"low":45,"high":149,"label":"loyalty software (self-serve)"}}]'::jsonb, '[{"goal":"nights","stage":"habit","minTier":"aggressive","weight":2,"role":"Reward repeat weeknight visits (a \"weeknight regular\" streak) so the slow night becomes a habit."},{"goal":"regulars","stage":"reward","minTier":"standard","weight":5,"role":"A points or visit-based program that makes coming back feel like progress."}]'::jsonb, '{"great":["qsr","cafe"],"avoid":{"seasonal":"One-visit-per-lifetime tourists can’t accumulate — concierge incentives matter more.","fineDining":"Points feel downmarket here — recognition-based VIP treatment instead.","preOpening":"No member base yet — defer to month 2–3."}}'::jsonb, null, 'active', 49),
  ('winback', 'winback', 'Lapsed-guest win-back', 'Win back quiet guests', 'Detect guests gone quiet 30/60/90 days and reach them with an escalating reason to return.', true, 'hybrid', 'AI drafts the messages; Apnosh defines the lapse logic and wires the triggers.', 'Winning back a lapsed guest costs a fraction of acquiring a new one.', null, '{"label":"Lapsed guests recovered","expect":"Cheaper than acquiring anyone new"}'::jsonb, '[{"amount":310,"kind":"one-time","cost":{"us":1.25,"offshore":1.5,"tools":3}}]'::jsonb, '[{"goal":"regulars","stage":"advocate","minTier":"lean","weight":4,"role":"An automatic offer to lapsed guests before they drift away for good.","because":"Winning back a lapsed guest costs a fraction of acquiring a new one."}]'::jsonb, '{"avoid":{"seasonal":"A tourist who visited once in August isn’t “lapsed” — they live 1,000 miles away.","preOpening":"No guest history to detect lapses in."}}'::jsonb, null, 'active', 50),
  ('referral', 'advocate', 'Referral & advocacy program', 'Turn regulars into promoters', 'A dual-sided referral mechanic plus a system to turn happy regulars into reviews and shareable UGC — the loop back to discovery.', false, 'hybrid', 'AI drafts the asks and reward copy; Apnosh designs the dual-sided mechanic and the timing of the ask.', 'Referred customers are measurably more valuable and stickier (Schmitt, Skiera & Van den Bulte, J. Marketing). Word-of-mouth is the #1 restaurant discovery channel — advocacy closes the loop.', null, '{"label":"Referred guests & guest UGC","expect":"Referred guests are ~16–25% more profitable and churn ~18% less (Schmitt et al.)"}'::jsonb, '[{"amount":290,"kind":"one-time","cost":{"us":1.5,"offshore":1}},{"amount":95,"kind":"monthly","cost":{"us":0.4,"offshore":0.5,"tools":5}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"aggressive","weight":1,"role":"Turn your new regulars into the next wave of guests."},{"goal":"regulars","stage":"advocate","minTier":"standard","weight":1,"role":"Rewards regulars for bringing friends, growing the loyal base from inside."}]'::jsonb, '{"great":["fineDining","neighborhood","cafe"]}'::jsonb, null, 'active', 51),
  ('friend-hook', 'advocate', 'First-timer bring-a-friend hook', 'Bring-a-friend reward', 'A single-use, first-timer-gated “bring a friend, both get a taco” pass that fires at the first visit and turns one new guest into two — code-keyed so it can only redeem once.', false, 'hybrid', 'AI drafts the pass copy; Apnosh designs the single-use, first-timer-gated mechanic and the redemption rule.', 'Refer-a-friend is the highest-trust acquisition channel, but this amplifies a stream you already created, never a standalone engine. Published redemption rates are thin (single digits to ~30%) — measure the real one. The friend’s plate is the owner’s food cost.', 'The reward is for a friend visit only — never tied to a review, rating or recommendation (platform rules forbid incentivized reviews).', '{"label":"Carried-friend visits","expect":"Amplifies an existing first-visit stream; ~zero on its own"}'::jsonb, '[{"amount":240,"kind":"one-time","cost":{"us":1,"offshore":6,"tools":5}},{"amount":75,"kind":"monthly","cost":{"us":0.2,"offshore":1}}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"lean","weight":5,"role":"Turn each first visit into two with a bring-a-friend pass."}]'::jsonb, '{"great":["neighborhood","qsr","cafe"],"avoid":{"fineDining":"A two-for token cheapens the premium positioning."}}'::jsonb, null, 'active', 52),
  ('birthday', 'retain', 'Birthday & anniversary club', 'Birthday treats', 'Collect the date at signup, send the treat automatically — the highest-redemption send there is.', true, 'hybrid', 'AI writes it once; the automation runs forever.', null, null, '{"label":"Birthday redemptions","expect":"The highest-redemption send there is"}'::jsonb, '[{"amount":190,"kind":"one-time","cost":{"us":0.75,"offshore":1,"tools":2}}]'::jsonb, '[{"goal":"regulars","stage":"reward","minTier":"standard","weight":4,"role":"An automatic birthday offer that brings a guest (and their table) in once a year."}]'::jsonb, '{"great":["bar"],"avoid":{"seasonal":"Near-zero redemption for one-time visitors — only worth it for the local base."}}'::jsonb, null, 'active', 53),
  ('seasonal-cal', 'anticipation', 'Seasonal plan', 'Plan the next 3 months', 'A quarter mapped in advance: holidays, local events, menu moments — so nothing is last-minute.', true, 'hybrid', 'AI generates the candidate calendar from local data; Apnosh curates it with you.', null, null, null, '[{"amount":220,"kind":"per-unit","unit":"quarter","cost":{"us":1,"offshore":0.5,"tools":3}}]'::jsonb, '[{"goal":"nights","stage":"draw","minTier":"aggressive","weight":1,"role":"Plan a quarter of rotating weeknight themes so the recurring night stays fresh."},{"goal":"regulars","stage":"lifecycle","minTier":"aggressive","weight":2,"role":"A quarter of planned seasonal reasons-to-return so the cadence never runs dry."}]'::jsonb, null, null, 'active', 54),
  ('concierge', 'awareness', 'Hotel & concierge outreach', 'Get hotels to send guests', 'Per-hotel incentive cards, a concierge kit, and a monthly visit cadence so the front desk sends you their guests.', false, 'apnosh', 'In-person relationship building — the least automatable item in the catalog.', 'For tourist-area rooms the front desk is a discovery channel; the playbook (shift-change visits, comp tastings) is documented relationship work.', null, '{"label":"Referrals from front desks","expect":"A relationship channel — builds over months, not days"}'::jsonb, '[{"amount":275,"kind":"one-time","cost":{"us":1,"offshore":1,"tools":15}},{"amount":265,"kind":"monthly","cost":{"us":1.25,"offshore":0.5,"tools":2}}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"aggressive","weight":1,"role":"Give nearby hotel front desks a reason to send their guests to you."}]'::jsonb, '{"great":["seasonal","fineDining"]}'::jsonb, null, 'active', 55),
  ('vip-comms', 'anticipation', 'VIP early-access sends', 'Treat your VIPs first', 'Regulars hear it first — new menu, ticketed nights, holiday books — before the public.', false, 'hybrid', 'AI drafts; Apnosh picks the segment and the moment.', null, null, null, '[{"amount":130,"kind":"per-unit","unit":"send","cost":{"us":0.5,"offshore":0.75,"tools":2}}]'::jsonb, '[{"goal":"regulars","stage":"lifecycle","minTier":"aggressive","weight":1,"role":"Personal one-to-one touches to your highest-value regulars so they feel seen."}]'::jsonb, '{"great":["fineDining"]}'::jsonb, null, 'active', 56),
  ('reporting', 'retain', 'Monthly report and check-in', 'See what is working', 'The numbers that matter (visits, list growth, reviews, revenue signals) + a 20-minute call on what to change.', true, 'hybrid', 'AI assembles the numbers; Apnosh reads them and tells you what to do differently.', null, null, '{"label":"The proving loop itself","expect":"Each month: what worked, what didn’t, and what we recommend you stop paying for"}'::jsonb, '[{"amount":150,"kind":"monthly","note":"included free in every bundle","cost":{"us":0.5,"offshore":1.25,"tools":3}}]'::jsonb, '[{"goal":"nights","stage":"habit","minTier":"standard","weight":1,"role":"Monthly read on whether covers on the named night are climbing, so you double down or change the draw."},{"goal":"regulars","stage":"own","minTier":"standard","weight":1,"role":"Monthly read on repeat rate, spend-per-guest, and which play is working."}]'::jsonb, '{"avoid":{"preOpening":"Nothing to report yet — launch milestones (list growth, RSVPs, press) instead."}}'::jsonb, null, 'active', 57),
  ('happy-hour-engine', 'convert', 'Daypart and happy-hour program', 'Run a happy hour', 'Design a recurring slow-time deal (happy hour, late night, lunch) with margin-safe math, then promote it every week.', false, 'apnosh', 'The margin math and the weekly promotion cadence are hands-on strategy work.', 'Daypart promotions fill predictable troughs without discounting the whole menu.', null, '{"label":"Covers on the slow daypart","expect":"A repeatable reason to come on the slow shift, promoted weekly"}'::jsonb, '[{"amount":325,"kind":"one-time","cost":{"us":1,"offshore":3},"note":"estimated price, confirm before launch"},{"amount":245,"kind":"monthly","cost":{"us":0.5,"offshore":3.5},"note":"estimated price, confirm before launch"}]'::jsonb, '[{"goal":"nights","stage":"draw","minTier":"lean","weight":4,"role":"Stand up a recurring slow-time deal (happy hour, late night, lunch) and promote it weekly, the real spine of filling a slow shift."}]'::jsonb, '{"great":["bar","neighborhood","qsr"]}'::jsonb, null, 'active', 58),
  ('ugc-rights', 'awareness', 'Guest photo reposting', 'Repost guest photos', 'Get written permission to repost guest photos and videos, then reshare them on a regular cadence.', false, 'hybrid', 'AI finds and drafts; a person confirms rights and posts.', 'Guest content is the cheapest, most trusted awareness fuel; rights make it safe to reuse.', null, '{"label":"Guest posts reshared","expect":"A steady stream of real guest photos reposted with permission"}'::jsonb, '[{"amount":95,"kind":"monthly","cost":{"us":0.2,"offshore":1.5},"note":"estimated price, confirm before launch"}]'::jsonb, '[{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":2,"role":"Repost real guest photos and videos with permission, the cheapest trusted way to reach new neighbors."},{"goal":"regulars","stage":"advocate","minTier":"standard","weight":1,"role":"Reshare your regulars posts so they feel seen and pull their friends in."}]'::jsonb, '{"great":["cafe","neighborhood","qsr"]}'::jsonb, null, 'active', 59),
  ('menu-photo-refresh', 'foundation', 'Menu and photo refresh', 'Refresh your photos', 'A recurring mini shoot and listings update so your photos match your current menu, season after season.', false, 'apnosh', 'On-site shoot plus the listings updates.', 'Stale photos drift from the real menu and quietly cost first visits.', null, '{"label":"Fresh photos live","expect":"Up-to-date photos whenever the menu changes"}'::jsonb, '[{"amount":425,"kind":"per-unit","unit":"quarter","cost":{"us":1,"offshore":2},"note":"estimated price, confirm before launch"}]'::jsonb, '[{"goal":"firstvisit","stage":"be-found","minTier":"aggressive","weight":1,"role":"Keep your photos matching your current menu so the page new guests check never looks stale."},{"goal":"reviews","stage":"listing","minTier":"standard","weight":1,"role":"Refresh the photos on the listing your rating sits on every season."}]'::jsonb, '{"great":["seasonal","fineDining"]}'::jsonb, null, 'active', 60),
  ('lto-launch', 'anticipation', 'New-item launch kit', 'Launch a new item', 'A productized launch for a new or limited-time item: a tease, the drop, and an encore push.', false, 'apnosh', 'A coordinated multi-step launch.', 'Menu news is a top reason both new and past guests come in.', null, '{"label":"Launch-week visits","expect":"A spike around a new or limited-time item"}'::jsonb, '[{"amount":385,"kind":"per-unit","unit":"launch","cost":{"us":1,"offshore":4},"note":"estimated price, confirm before launch"}]'::jsonb, '[{"goal":"nights","stage":"draw","minTier":"standard","weight":1,"role":"Launch a limited-time item with a tease, a drop, and an encore, a fresh reason to come on a slow night."},{"goal":"firstvisit","stage":"get-discovered","minTier":"standard","weight":1,"role":"Use menu news to pull in new guests who have not tried you yet."}]'::jsonb, '{"great":["qsr","cafe","neighborhood"]}'::jsonb, null, 'active', 61),
  ('staff-advocacy', 'advocate', 'Staff review and share kit', 'Get your team asking', 'Train and equip your team to ask for the review or signup at the table and reshare on their own social.', false, 'apnosh', 'Training and scripts for the team.', 'Staff are the highest-trust, zero-cost channel and are usually untapped.', null, '{"label":"Reviews and signups from staff asks","expect":"Front-of-house reliably asking and resharing"}'::jsonb, '[{"amount":190,"kind":"one-time","cost":{"us":0.75,"offshore":1},"note":"estimated price, confirm before launch"}]'::jsonb, '[{"goal":"reviews","stage":"ask","minTier":"standard","weight":1,"role":"Train your team to ask for the review at the table, the highest-trust ask there is."}]'::jsonb, '{"great":["neighborhood","cafe","bar"]}'::jsonb, null, 'active', 62),
  ('google-food-order', 'foundation', 'Google order and reserve links', 'Google order button', 'Wire the Order and Reserve buttons on your Google profile and Maps to your own ordering and booking.', false, 'apnosh', 'Technical wiring on Google and your site.', 'The Google action buttons are a major conversion surface most listings leave on default.', null, '{"label":"Orders and bookings from Google","expect":"The Order and Reserve buttons point to your own site"}'::jsonb, '[{"amount":165,"kind":"one-time","cost":{"us":0.5,"offshore":1},"note":"estimated price, confirm before launch"}]'::jsonb, '[{"goal":"firstvisit","stage":"capture-return","minTier":"standard","weight":1,"role":"Point the Order and Reserve buttons on Google to your own site so a ready-to-buy guest converts."}]'::jsonb, '{"great":["qsr","ghost"]}'::jsonb, null, 'active', 63)
